diff --git c/include/simdjson/dom/element-inl.h i/include/simdjson/dom/element-inl.h
index 1f071da608..fee647551d 100644
--- c/include/simdjson/dom/element-inl.h
+++ i/include/simdjson/dom/element-inl.h
@@ -185,6 +185,16 @@ simdjson_inline dom::array::iterator simdjson_result<dom::element>::end() const

 namespace dom {

+static simdjson_inline bool element_json_pointer_has_valid_syntax(std::string_view json_pointer) noexcept {
+  if (json_pointer.empty() || json_pointer[0] != '/') { return false; }
+  for (size_t escape = json_pointer.find('~'); escape != std::string_view::npos; escape = json_pointer.find('~', escape + 1)) {
+    if (escape + 1 >= json_pointer.length() || (json_pointer[escape + 1] != '0' && json_pointer[escape + 1] != '1')) {
+      return false;
+    }
+  }
+  return true;
+}
+
 //
 // element inline implementation
 //
@@ -383,8 +393,8 @@ inline simdjson_result<element> element::at_pointer(std::string_view json_pointe
     case internal::tape_type::START_ARRAY:
       return array(tape).at_pointer(json_pointer);
     default: {
-      if(!json_pointer.empty()) { // a non-empty string is invalid on an atom
-        return INVALID_JSON_POINTER;
+      if(!json_pointer.empty()) { // a non-empty string on an atom does not match anything
+        return element_json_pointer_has_valid_syntax(json_pointer) ? NO_SUCH_FIELD : INVALID_JSON_POINTER;
       }
       // an empty string means that we return the current node
       dom::element copy(*this);
